window.DQ_INDEX=[{"u":"articles/adenoid-face.html","t":"口呼吸・お口ぽかん、顔つきや歯並びに影響するの？","d":"お口ぽかん（口呼吸）は顔つきや歯並びに影響するの？アデノイド肥大との関係を論文をもとに、悪循環が起きる仕組みと家庭でできる対策を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/baby-chewing.html","t":"赤ちゃんの\"噛む力\"っていつ育つの？","d":"離乳食、いつから固いものを食べさせていい？赤ちゃんの咀嚼機能がどう発達していくのかを研究をもとに解説。月齢に合わせた進め方のコツを現役歯科医師がまとめます。","c":"食育"},{"u":"articles/baby-led-weaning.html","t":"手づかみ食べ（BLW）ってどうするの？栄養は足りる？","d":"赤ちゃんの手づかみ食べ（BLW）。栄養は足りる？窒息は大丈夫？始め方は？修正版BLWの研究をもとに、進め方の注意点と歯科医がすすめる理由を現役歯科医師が解説します。","c":"食育"},{"u":"articles/breastfeeding-teeth.html","t":"母乳育児って歯並びにいいの？","d":"母乳育児は歯並びにいいの？48研究をまとめたメタ解析をもとに、母乳と不正咬合（歯並び・かみ合わせの乱れ）の関係、卒乳後に気をつけたいことを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/bristle-stiffness.html","t":"歯ブラシの硬さは\"やわらかめ\"と\"ふつう\"どっち？","d":"硬い毛ほど歯垢は落ちるが歯ぐきは傷つく——研究が示すトレードオフを正直に解説。ランダム化比較試験とシステマティックレビューをもとに、現役歯科医師がフェアにまとめます。","c":"オーラルケア"},{"u":"articles/brush-head-size.html","t":"歯ブラシのヘッドは小さい方がいいの？","d":"コンパクトヘッドは本当に有利？ロボット実験では磨き方によって結果が逆転し、ヒトでの比較試験はほとんどありません。エビデンスの限界まで含めて現役歯科医師がフェアに解説します。","c":"オーラルケア"},{"u":"articles/brush-replacement.html","t":"歯ブラシっていつ替えるの？","d":"歯ブラシは何ヶ月で交換すべき？古いブラシは本当に落ちが悪いのか。3ヶ月使用ブラシと新品を比べた研究や、毛先の開き・細菌汚染の論文をもとに、現役歯科医師がフェアに解説します。","c":"オーラルケア"},{"u":"articles/brushing-method.html","t":"歯の磨き方って結局どれが正解？","d":"バス法、スクラビング法、フォーンズ法…どの磨き方が一番いいの？システマティックレビューとネットワークメタ解析をもとに、現役歯科医師がフェアに解説。結論は「決定的な差は示されていない","c":"オーラルケア"},{"u":"articles/brushing-time.html","t":"歯磨きは何分・1日何回すればいいの？","d":"「2分間・1日2回」はどこまで正しい？1分と2分を比べたメタ解析、ブラッシング回数とむし歯の関係を調べた33件のメタ解析をもとに、現役歯科医師が数字ごとフェアに解説します。","c":"オーラルケア"},{"u":"articles/bruxism-splint.html","t":"歯ぎしりのマウスピース（スプリント）ってどうするの？","d":"歯ぎしり対策のマウスピース（スプリント）は本当に効くのか。コクランレビューをもとに、歯ぎしり自体への効果と、歯の摩耗を守る役割の違いを現役歯科医師が正直に解説します。","c":"歯ぎしり"},{"u":"articles/canker-sore.html","t":"口内炎（アフタ）って何で治すの？","d":"繰り返す口内炎（再発性アフタ性口内炎）はどうやって治すの？システマティックレビューをもとに、被覆材や塗り薬・レーザーなど痛みを和らげる治療法と、セルフケアのコツを現役歯科医師が解説","c":"オーラルケア"},{"u":"articles/ceramic-crown.html","t":"セラミックの被せ物ってどのくらいもつの？","d":"白くてきれいなセラミックの被せ物、でも「割れやすい」って本当？オールセラミックの5年生存率を従来の金属セラミックと比べ、長持ちさせるコツを論文をもとに現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/ceramic-lifespan.html","t":"セラミックの被せ物、何年もつ？","d":"セラミックの被せ物・ブリッジ・ラミネートベニアは何年もつのか。オールセラミックとメタルセラミックの5年生存率、ジルコニアやモノリシックの違いを、システマティックレビューをもとに現役","c":"自費・専門治療"},{"u":"articles/ceramic-vs-metal-update.html","t":"オールセラミック vs メタルセラミック、その後の10年で何が更新されたか","d":"2015年Sailerのシステマティックレビューは単冠の5年生存率を示しました。では2020年のエンドクラウンのメタアナリシスはその「更新版」なのか。結論、同じ問いではありません。","c":"補綴"},{"u":"articles/charcoal-toothpaste.html","t":"炭（チャコール）の歯磨き粉って安全？効果ある？","d":"SNSで話題の炭（チャコール）歯みがき粉。本当に白くなる？安全なの？システマティックレビューをもとに、効果のエビデンスと研磨リスクを現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/chewing.html","t":"「30回噛みなさい」って本当に効果あるの？","d":"よく噛むと食べ過ぎを防げるのか。学術研究をもとに、咀嚼回数とエネルギー摂取・空腹ホルモンの関係を現役歯科医師が解説します。","c":"食と歯"},{"u":"articles/chlorhexidine-update.html","t":"クロルヘキシジン洗口液、いま何がわかっているのか","d":"CHX洗口液は「歯肉炎に効く」で止まっていないか。2017年コクランレビューと2020年ナラティブレビューを読み比べ、プラーク・歯肉炎・歯周炎・着色・アナフィラキシー、そして日本の","c":"オーラルケア"},{"u":"articles/chx-mouthwash.html","t":"クロルヘキシジンのうがい薬って効くの？使い続けて大丈夫？","d":"クロルヘキシジン(CHX)洗口液は歯垢や歯肉炎に効くの？長く使って平気？コクランレビューをもとに、プラーク抑制効果と着色などの副作用、上手な使い方を現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/clear-aligner-adult.html","t":"大人のマウスピース矯正、郵送型ってどうなの？","d":"大人のマウスピース矯正（クリアアライナー）。軽度〜中等度には選択肢ですが、歯を大きく動かす複雑な症例では限界があると報告されています。とくに郵送型（対面診査なし）の注意点を、現役歯","c":"矯正"},{"u":"articles/composite-vs-amalgam.html","t":"白い詰め物と銀歯、どっちがいいの？","d":"白い詰め物（コンポジットレジン）と銀歯（アマルガム）、結局どっちが長持ち？コクランレビューをもとに、失敗リスク・二次むし歯・見た目・安全性の違いを現役歯科医師が中立に解説します。","c":"オーラルケア"},{"u":"articles/cracked-tooth.html","t":"歯にヒビ（亀裂）が入るとどうなるの？","d":"噛むとズキッと痛むのに、レントゲンでは異常なし。歯のヒビ（クラックトゥース／歯の破折）が心配な方へ。レビュー論文をもとに、原因・見つけ方・進行を防ぐ対処を現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/dental-erosion.html","t":"酸蝕歯（歯が酸で溶ける）ってどうするの？","d":"酸っぱい飲食物で歯が溶ける「酸蝕歯」。すぐ歯みがきしていい？システマティックレビューをもとに、酸蝕歯の予防・進行を抑えるコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/denture-adhesive.html","t":"入れ歯安定剤ってどう使うの？選び方は？","d":"入れ歯安定剤は使ってもいいの？選び方や使い方のコツは？維持力や満足度を調べた研究をもとに、上手な使い方と注意点を現役歯科医師が解説します。","c":"入れ歯"},{"u":"articles/denture-cleaning.html","t":"入れ歯の洗浄って結局どうするの？ブラシと洗浄剤どっち？","d":"入れ歯はブラシでこするだけでいい？洗浄剤に浸けるべき？コクランレビューをもとに、機械的清掃と化学洗浄の使い分け、毎日のお手入れの基本を現役歯科医師が解説します。","c":"入れ歯"},{"u":"articles/denture-night.html","t":"入れ歯は夜つけたまま寝ていいの？","d":"入れ歯は夜も入れたまま寝て大丈夫？高齢者を対象にした研究をもとに、夜間の義歯装着と肺炎リスクの関係、外して保管するときのお手入れを現役歯科医師が解説します。","c":"入れ歯"},{"u":"articles/denture-stomatitis.html","t":"入れ歯の下が赤い・痛い…義歯性口内炎ってどうするの？","d":"入れ歯を外すと歯ぐきが赤い、ヒリヒリ痛む。それは義歯性口内炎かもしれません。夜間の装着やカンジダ菌との関係、清掃と対処のコツを現役歯科医師が論文をもとに解説します。","c":"入れ歯"},{"u":"articles/diabetes-implant.html","t":"糖尿病でもインプラントできるの？","d":"糖尿病だとインプラントは無理？と諦めていませんか。血糖コントロールとインプラント成功率の関係を論文をもとに、治療前に整えておきたいポイントを現役歯科医師が解説します。","c":"インプラント"},{"u":"articles/dry-mouth.html","t":"ドライマウス（口腔乾燥）ってどうするの？","d":"口の中がネバつく・乾く「ドライマウス」。原因や、保湿ジェル・洗口液・唾液を出す工夫はどこまで効くの？アンブレラレビューをもとに、現役歯科医師が対処法をやさしく解説します。","c":"オーラルケア"},{"u":"articles/early-childhood-caries.html","t":"乳歯の虫歯、何が原因でどう防ぐの？","d":"乳歯の虫歯（乳幼児う蝕）は何が原因？ミュータンス菌や既にある虫歯がリスクになるって本当？子どもの虫歯の予防のコツを、論文をもとに現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/early-ortho-class2.html","t":"出っ歯の子、早めに矯正した方がいいの？","d":"子どもの出っ歯（上顎前突）は早めに矯正すべき？早期の2段階治療のメリットや、前歯のケガのリスクとの関係を、コクランレビューをもとに現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/electric-toothbrush.html","t":"電動歯ブラシと手用、どっちがいいの？論文でわかる結論","d":"電動歯ブラシは手用より本当に良い？コクランレビューなど信頼性の高い論文をもとに、歯垢・歯肉炎の減り方、音波式と回転式の違い、選び方まで歯科の視点で正直に解説します。","c":"オーラルケア"},{"u":"articles/floss-interdental.html","t":"フロスと歯間ブラシ、どっちがいいの？論文でわかる使い分け","d":"フロスと歯間ブラシ、買うべきはどっち？コクランレビューをもとに、歯肉炎への効果とすき間による正しい使い分け、サイズ選びのコツを解説します。","c":"オーラルケア"},{"u":"articles/fluoride-ppm.html","t":"歯磨き粉のフッ素、何ppm選べばいいの？","d":"フッ素は濃い方が効くの？コクランレビューをもとに、フッ素濃度とむし歯予防効果の関係、大人・子どもで選ぶべきppm、使い方のコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/fluoride-rinse.html","t":"フッ素のうがい（フッ化物洗口）って子どもに必要？","d":"学校や家庭でのフッ化物洗口、本当に子どものむし歯予防になるの？コクランレビューをもとに、効果の大きさ・始める年齢・使い方の注意点を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/fluoride-safety.html","t":"フッ素は体に悪いの？安全性を論文で冷静に整理","d":"「フッ素は危険」「体に悪い」は本当？結論はフッ素は","c":"オーラルケア"},{"u":"articles/fluoride-varnish-nma-update.html","t":"歯医者で塗るフッ素、本当に効くのはどれ？","d":"子どものむし歯予防で歯科医院が塗る「フッ素」。8種類の塗り方を比べた最新のネットワークメタ解析では、対照より明確に効いたのは一部だけでした。現役歯科医師がエビデンスの中身を中立に解","c":"昔の常識 vs 最新"},{"u":"articles/fluoride-varnish.html","t":"歯医者さんのフッ素塗布ってどのくらい虫歯を防ぐの？","d":"歯科医院で塗るフッ素（フッ化物バーニッシュ）は、市販の歯磨き粉と何が違い、どのくらい虫歯を防ぐのか。コクランレビューをもとに、効果の目安と受ける頻度を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/fluorosis.html","t":"フッ素の摂りすぎで歯に白い斑点？（歯のフッ素症）","d":"子どもの歯に白い斑点。フッ素の摂りすぎ（歯のフッ素症）が心配な方へ。コクランレビューをもとに、適量なら安全な理由、年齢に合った濃度と量、飲み込ませないコツを現役歯科医師が解説します","c":"子どもの歯"},{"u":"articles/full-mouth-vs-quadrant.html","t":"歯周病治療は一気にやった方がいいの？","d":"歯周病の歯石取りは一気にやる方が効果的なの？フルマウス一括法と分割法（1回1ブロック）の違いをコクランレビューをもとに、現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/gingivitis-plaque.html","t":"歯みがきをサボると歯ぐきはどうなるの？","d":"歯みがきをやめると歯ぐきはどう変わる？プラークと歯肉炎の関係を調べた古典的な研究をもとに、歯肉炎が起こるまでの日数と回復のしくみを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/gum-recession.html","t":"歯茎が下がる（歯肉退縮）のはなぜ？戻せるの？","d":"歯茎が下がって歯が長く見える「歯肉退縮」。自然には戻らないの？システマティックレビューをもとに、原因・進行を止める方法・外科で覆える場合を現役歯科医師が解説します。","c":"全身と歯"},{"u":"articles/implant-20year.html","t":"インプラントの20年生存率は93.0%｜前向き研究のみのSR/MAを読む","d":"20年以上追跡した前向き研究のみを対象としたシステマティックレビュー/メタ解析（2026）で、インプラント20年生存率は93.0%（95%CI 91.6-94.1）、プール平均MB","c":"インプラント"},{"u":"articles/implant-lifespan.html","t":"インプラントって何年もつの？","d":"インプラントは何年もつ？長期の追跡研究をもとに、10年以上の累積生存率、長持ちさせるために欠かせないメンテナンスのポイントを現役歯科医師が正直に解説します。","c":"インプラント"},{"u":"articles/implant-maintenance.html","t":"インプラントのメインテナンスってどのくらいの頻度？","d":"せっかく入れたインプラント、放っておくと抜けることも。定期メンテナンスがインプラント周囲炎をどれだけ防ぐのか、通う頻度の目安を論文をもとに現役歯科医師が解説します。","c":"インプラント"},{"u":"articles/implant-overdenture.html","t":"下の総入れ歯が動く…インプラントで固定する治療は？","d":"下の総入れ歯がしゃべると浮く、噛むとズレる。インプラントで固定するオーバーデンチャーとは？従来の入れ歯との満足度・QOLの違いを、現役歯科医師が論文をもとに解説します。","c":"入れ歯"},{"u":"articles/interdental-cleaning-update.html","t":"歯間清掃は結局どれがいいのか","d":"フロスvs歯間ブラシvsウォーターフロス。デバイスごとにバラバラに評価されてきた歯間清掃を、2020年のネットワークメタ解析が横断比較しようとした。しかし結論は「強い結論は出せない","c":"オーラルケア"},{"u":"articles/intraoral-scanner.html","t":"歯型取りが光スキャンに？口腔内スキャナーの精度は？","d":"あの苦しい歯型取りがカメラで撮るだけに。口腔内スキャナー（IOS）は従来の型取りとどこまで精度が並ぶのか、苦手な場面はどこか、論文をもとに現役歯科医師が解説します。","c":"インプラント"},{"u":"articles/keep-teeth-30y.html","t":"一生自分の歯で噛むにはどうするの？","d":"自分の歯を一生残すことはできる？30年間、定期メンテナンスを続けた人を追った研究をもとに、失う歯をどこまで減らせるのか、そのために必要なことを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/kids-chewing-obesity.html","t":"早食いの子は太りやすい？","d":"早食いの子は太りやすいの？小学4年生を3年間追いかけた日本のコホート研究などをもとに、食べる速さと過体重の関係、家庭でできる『ゆっくり噛んで食べる』工夫を現役歯科医師が解説します。","c":"食育"},{"u":"articles/kids-malocclusion.html","t":"子どもの歯並び、乳歯のうちからどうするの？","d":"乳歯のうちから歯並びは気にすべき？子どもの不正咬合の世界的な有病率や、家庭でできること・受診の目安を、論文をもとに現役歯科医師がやさしく解説します。","c":"子どもの歯"},{"u":"articles/mft.html","t":"MFT（口の体操）ってどうするの？歯並びに効くの？","d":"MFT（口腔筋機能療法・口の体操）って歯並びに効くの？矯正の補助としての有効性を論文をもとに、何をする訓練なのか、向いているケースを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/mi-paste-remin.html","t":"初期虫歯（白い斑点）は削らず治せるの？","d":"歯の白い斑点（初期虫歯）は削らずに戻せるの？CPP-ACP（MIペースト）の再石灰化効果を検証した論文をもとに、白斑への働きと家庭でのケアのコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/mouth-breathing.html","t":"お口ぽかん（口呼吸）って顔の発育に影響するの？","d":"子どもの口呼吸は顔やあごの発育に影響するのか。BMC Oral Healthの研究をもとに、口呼吸とあご・気道の関係、早めに相談すべきサインを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/mouthwash.html","t":"マウスウォッシュは歯みがきの代わりになるの？","d":"洗口液（マウスウォッシュ）だけで歯みがきの代わりになる？コクランレビューなどをもとに、洗口液の本当の効果と正しい使い方、CHXとリステリンの違いを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/oil-pulling.html","t":"オイルプリング（油うがい）って効くの？","d":"ココナッツオイルなどでうがいするオイルプリングは歯やお口に効くの？システマティックレビューをもとに、プラークや歯ぐきへの効果と、エビデンスの限界を現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/oral-care-pneumonia.html","t":"口腔ケアで肺炎って本当に防げるの？","d":"口腔ケアで誤嚥性肺炎は防げる？施設高齢者を対象にした研究をもとに、専門的な口腔ケアと肺炎予防の関係を現役歯科医師が解説します。","c":"高齢と歯"},{"u":"articles/oral-frailty-update.html","t":"オーラルフレイルは、いま何がわかっているのか","d":"オーラルフレイルは日本の柏スタディ（Tanaka 2018）で6項目の操作的定義として提示され、2021年のLancet Healthy Longevityのシステマティックレビュ","c":"高齢と歯"},{"u":"articles/oral-frailty.html","t":"オーラルフレイルってどうするの？放置するとどうなる？","d":"オーラルフレイル(口の衰え)ってなに？放置するとどうなる？高齢者を追った研究をもとに、身体の衰えや死亡リスクとの関連、早めに気づいて対処するコツを現役歯科医師が解説します。","c":"高齢と歯"},{"u":"articles/oral-hypofunction.html","t":"口腔機能低下症って何？チェック方法は？","d":"むせる、食べこぼす、滑舌が落ちた。加齢による口の衰えは「口腔機能低下症」として7項目で診断されます。どんな検査で何がわかるのか、家庭での気づきのサインを現役歯科医師が論文をもとに解","c":"高齢と歯"},{"u":"articles/osa-oral-appliance.html","t":"いびき・睡眠時無呼吸の歯科マウスピース（OA）ってどうするの？","d":"歯科で作るマウスピース（口腔内装置・OA）はいびきや睡眠時無呼吸に効くの？コクランレビューをもとに、OAの効果とCPAPとの違い、向いている人を現役歯科医師が解説します。","c":"歯ぎしり"},{"u":"articles/pacifier-malocclusion-update.html","t":"おしゃぶりと不正咬合、エビデンスはどこまで言えるのか","d":"「おしゃぶりは開咬・交叉咬合の原因」は、実はメタアナリシスで裏づけられていません。2018年のシステマティックレビューと2022年の有病率レビューを読み比べ、RRが存在しないこと、","c":"子どもの歯"},{"u":"articles/pacifier-sids.html","t":"おしゃぶりって使っていいの？SIDS対策になる？","d":"おしゃぶりは歯並びに悪い？でもSIDS（乳幼児突然死症候群）対策になるって本当？就寝時のおしゃぶりと乳幼児突然死のリスクの関係を、論文をもとに現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/pacifier-thumb.html","t":"指しゃぶり・おしゃぶり、歯並びに影響するの？","d":"指しゃぶりやおしゃぶりは歯並びに悪い？いつまでにやめる？SIDS予防の利点との功罪も含め、現役歯科医師が論文をもとに卒業の目安とやめさせ方を解説します。","c":"子どもの歯"},{"u":"articles/peri-implantitis-prevalence.html","t":"インプラント周囲炎は結局どれくらい起きるのか — 2014年の常識と最新メタ解析","d":"「インプラント周囲炎は約22%」——2014年のDerksらの数字は今も生きているのか。2022年のメタ解析（患者レベル19.53%／インプラントレベル12.53%）と並べ、なぜ数","c":"インプラント"},{"u":"articles/peri-implantitis.html","t":"インプラント周囲炎ってどのくらい起こるの？","d":"インプラントを入れたあとに起こる「周囲炎」。どのくらいの人に起こるのか、天然歯の歯周病と何が違うのか、日々のケアで防げるのかを、現役歯科医師が論文をもとに解説します。","c":"インプラント"},{"u":"articles/perio-diabetes.html","t":"歯周病を治すと糖尿病もよくなるの？","d":"歯周病の治療で糖尿病の数値は変わる？歯周治療とHbA1cの関係を調べたコクランレビューをもとに、口の健康と血糖のつながりを現役歯科医師が正直に解説します。","c":"全身と歯"},{"u":"articles/perio-heart.html","t":"歯周病って心臓の病気と関係あるの？","d":"歯周病は心臓・血管の病気とどう関わるの？ヨーロッパ歯周病連盟のコンセンサスをもとに、歯周炎が心血管疾患の修飾できるリスク因子とされる理由と、今日からできる対策を現役歯科医師が解説し","c":"全身と歯"},{"u":"articles/perio-staging.html","t":"自分の歯周病はどのくらい進んでるの？","d":"歯周病の進行度は「ステージ」と「グレード」で評価します。2018年の新しい国際分類をもとに、自分の歯周病がどのくらい進んでいるのか、何を見て判断するのかを現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/perioperative-oral.html","t":"手術前の歯科受診（周術期口腔機能管理）ってどうするの？","d":"大きな手術の前になぜ歯医者？周術期口腔機能管理の目的を、日本の大規模データをもとに解説。術後肺炎との関係、受診の流れ、家庭でのケアを現役歯科医師がまとめます。","c":"高齢と歯"},{"u":"articles/power-brush-type-update.html","t":"電動歯ブラシ、回転式と音波式どっちがいい？","d":"電動歯ブラシの「回転式（オシレーティング・ロテーティング）」と「音波式（高頻度）」。プラーク除去を比べた最新のシステマティックレビューでは、回転式がわずかに優位でした。差の大きさと","c":"昔の常識 vs 最新"},{"u":"articles/precision-endo.html","t":"精密根管治療で何が変わる？論文で見る成功率","d":"マイクロスコープやラバーダムを使う「精密根管治療」。根管治療の成功率や、精度を高める要素を、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/probiotics-oral.html","t":"乳酸菌（プロバイオティクス）は虫歯・歯周病に効くの？","d":"口腔用の乳酸菌・プロバイオティクスは虫歯や歯周病に効くの？システマティックレビュー＆メタ分析をもとに、むし歯菌や歯ぐきへの効果と限界を現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/pulp-capping-mta.html","t":"神経を残す治療（直接覆髄）ってどうするの？MTAって？","d":"虫歯が神経に近いとき、神経を残す「直接覆髄」という選択肢があります。使われる材料MTAと水酸化カルシウムの違いを、論文をもとに現役歯科医師が解説します。","c":"歯内療法"},{"u":"articles/recall-interval.html","t":"歯の定期検診って何ヶ月ごとに行けばいいの？","d":"定期検診は半年ごとが正解？コクランレビューをもとに、検診間隔と虫歯・歯周病アウトカムの関係、リスクに応じた通院ペースの決め方を現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/regular-cleaning.html","t":"定期的な歯のクリーニングって意味あるの？","d":"歯のクリーニングは定期的に通う価値がある？プロのケアと清掃指導を6年続けた人を追った研究をもとに、むし歯や歯ぐきの後退がどう変わるかを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/resin-infiltration.html","t":"隣の歯との間の初期虫歯、削らず止められるの？","d":"歯と歯の間にできた初期の虫歯、いきなり削るしかないの？削らずに進行を抑える「レジン浸潤(Icon)」という選択肢があります。研究をもとに、その効果と向き不向きを現役歯科医師が解説し","c":"オーラルケア"},{"u":"articles/rme-enuresis.html","t":"おねしょが治らない…上顎拡大で改善するの？","d":"治りにくいおねしょ（夜尿症）に、歯科の上顎急速拡大（RME）が関係するって本当？上あごの拡大と夜尿の関係を、論文をもとに現役歯科医師がやさしく解説します。","c":"子どもの歯"},{"u":"articles/root-canal-success-update.html","t":"根管治療の成功率は、結局いくつなのか","d":"根管治療の成功率「◯%」は、判定基準を決めなければ意味を持たない。Ng 2007のシステマティックレビューと、2022年の更新版（Burns）を読み比べ、strict 82.0%と","c":"歯内療法"},{"u":"articles/root-canal-success.html","t":"根管治療の成功率ってどのくらいなの？","d":"根管治療（歯の神経の治療）の成功率はどのくらい？系統的レビューをもとに、初回治療の成功率、成功を左右する条件、再治療の考え方を現役歯科医師が解説します。","c":"歯内療法"},{"u":"articles/rubber-dam.html","t":"根管治療のラバーダムって本当に必要なの？","d":"根管治療で口にかけるゴムのシート「ラバーダム」。本当に必要？歯の生存率を調べた研究をもとに、その役割と効果を現役歯科医師がやさしく解説します。","c":"歯内療法"},{"u":"articles/sdf-silver.html","t":"サホライド（SDF）で虫歯の進行は止められるの？黒くなる？","d":"子どもの虫歯に塗る「サホライド（38%SDF）」は本当に進行を止められるのか、そして黒くなるのはなぜか。系統的レビューをもとに、効果と見た目のトレードオフを現役歯科医師が正直に解説","c":"子どもの歯"},{"u":"articles/sealant-primary-update.html","t":"乳歯のシーラントは本当に効く？最新の研究で見直し","d":"子どもの奥歯に詰める「シーラント（予防充填）」。永久歯では有効性が確立していますが、乳歯（乳臼歯）に限ると質の高い研究が不足しているという最新のシステマティックレビューを、現役歯科","c":"昔の常識 vs 最新"},{"u":"articles/sealant.html","t":"奥歯の溝を埋めるシーラントって虫歯予防になるの？","d":"子どもの奥歯の溝を樹脂で埋める「シーラント」。本当にむし歯予防になるのか、コクランレビューをもとに効果と限界、いつ受けるべきかを現役歯科医師がやさしく解説します。","c":"子どもの歯"},{"u":"articles/sensitivity-toothpaste.html","t":"知覚過敏の歯磨き粉（硝酸カリウム）って効くの？","d":"冷たいものでしみる知覚過敏。シュミテクトなどに入っている硝酸カリウムは本当に効くのか、どのくらいの期間で効いてくるのかを、現役歯科医師がコクランレビューをもとに解説します。","c":"オーラルケア"},{"u":"articles/shortened-dental-arch.html","t":"奥歯がなくても大丈夫？短縮歯列って？","d":"一番奥の歯を失った、入れ歯を作るか迷う。実は奥歯が全部そろっていなくても機能を保てるという「短縮歯列」の考え方があります。どこまで残せばいいのか、現役歯科医師が論文をもとに解説しま","c":"入れ歯"},{"u":"articles/single-multi-visit.html","t":"根管治療って1回で終わらせていいの？","d":"根管治療は1回で終わる？それとも複数回に分けるべき？単回法と複数回法を比べたコクランレビューをもとに、治り方の違いを現役歯科医師が解説します。","c":"歯内療法"},{"u":"articles/smoking-implant-update.html","t":"喫煙はインプラントをどれだけ失敗させるのか｜「本数」で見た最新の知見","d":"「喫煙者は失敗しやすい」から「喫煙量で差があるか」へ。2015年のChrcanovicらのメタ解析（107研究）と2020年のNaseriらの本数別メタ解析（23研究）を比較し、歯","c":"インプラント"},{"u":"articles/smoking-implant.html","t":"タバコを吸っているとインプラントは失敗しやすいの？","d":"喫煙はインプラント治療にどう影響するのか。禁煙しないと入れられないのか、失敗リスクはどれくらい上がるのかを、現役歯科医師が論文をもとにフェアに解説します。","c":"インプラント"},{"u":"articles/spt-maintenance.html","t":"歯周病が治った後のメンテナンスって必要なの？","d":"歯周病の治療が終わったら通院はもう終わり？いいえ、その後の定期メンテナンス(SPT)こそが歯を守るカギです。コクランレビューをもとに、なぜ続ける必要があるのかを現役歯科医師が解説し","c":"歯周病"},{"u":"articles/spt-tooth-loss.html","t":"歯周メンテ(SPT)ってサボると歯を失うの？","d":"歯周病のメンテナンス、忙しくてつい間隔が空いてしまう…。実は通院を守れるかどうかで歯の残り方が変わります。研究をもとに、SPTの遵守と歯の喪失の関係を現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/srp-scaling.html","t":"歯石取り（SRP）ってどのくらい効果あるの？","d":"歯ぐきの中の歯石取り（SRP）は本当に効くの？歯周ポケットへの効果を調べた研究をもとに、SRPで何がどこまで改善するのか、通院前に知っておきたいことを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/sugar-caries.html","t":"砂糖をどれくらい減らせば虫歯にならないの？","d":"砂糖と虫歯の関係を、WHOのガイドラインの根拠にもなった系統的レビューをもとに解説。1日どれくらいまでなら虫歯が増えにくいのか、遊離糖の考え方を現役歯科医師が正直に説明します。","c":"食と歯"},{"u":"articles/sugar-gingivitis-update.html","t":"砂糖はむし歯だけ？じつは歯ぐきの炎症にも","d":"砂糖はむし歯の原因として知られますが、最新のシステマティックレビューでは「砂糖を減らすと歯ぐきの炎症も減る」という関連が示されました。歯みがきとは別の切り口の予防を、現役歯科医師が","c":"昔の常識 vs 最新"},{"u":"articles/tapered-bristles.html","t":"テーパー毛（先細毛）とラウンド毛、どっちがいいの？","d":"先細毛はラウンド毛より本当に優秀？システマティックレビューでは「プラーク除去に差なし」と報告されています。歯ぐきへのやさしさは？現役歯科医師が論文をもとにフェアに解説します。","c":"オーラルケア"},{"u":"articles/teeth-eruption.html","t":"赤ちゃんの歯っていつ生える？生えないと心配？","d":"赤ちゃんの歯はいつ生えるの？なかなか生えないと心配？系統的レビューをもとに、乳歯が生える時期・順番、地域差、様子を見ていい目安を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/teeth-longevity.html","t":"歯の数と寿命って関係あるの？","d":"歯が多く残っている人は長生き？残存歯数や噛み合わせと死亡リスクの関係を、日本の追跡研究をもとに解説。今日からできる歯を守るケアを現役歯科医師がまとめます。","c":"高齢と歯"},{"u":"articles/tongue-halitosis.html","t":"舌みがきって口臭に効くの？","d":"舌の掃除で口臭は本当に減るのか。コクランレビューをもとに、舌クリーナーが揮発性硫黄化合物（口臭のもと）に与える効果と、その持続性の限界を現役歯科医師が正直に解説します。","c":"口臭"},{"u":"articles/tongue-tie.html","t":"舌小帯って切った方がいいの？授乳がうまくいかない時","d":"赤ちゃんの舌小帯（舌のスジ）、切った方がいいの？コクランレビューをもとに、舌小帯切除と授乳・乳頭痛の関係、判断のポイントを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/tooth-autotransplant.html","t":"自家歯牙移植ってどうなの？","d":"親知らずなど自分の歯を、抜けた場所へ移す「自家歯牙移植」。生存率や向いているケースを、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/water-flosser.html","t":"ウォーターフロス（口腔洗浄機）って効くの？","d":"水流で歯の間を洗う「ウォーターフロス（口腔洗浄機）」。プラークは落ちるの？歯ぐきには？糸のフロスの代わりになる？システマティックレビューをもとに現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/whitening-concentration.html","t":"ホワイトニングは「濃いほど白い」？","d":"ホワイトニングの薬剤は濃いほうがよく白くなる——そう思われがちですが、システマティックレビューの結果は少し違いました。濃度と「しみる（知覚過敏）」・色の変化の関係を、現役歯科医師が","c":"ホワイトニング"},{"u":"articles/whitening-home-vs-office.html","t":"ホームとオフィス、ホワイトニングはどっちがいい？","d":"自宅で行うホームホワイトニングと、歯科医院のオフィスホワイトニング。効果や「しみる」リスクに差はあるのでしょうか。システマティックレビューをもとに、現役歯科医師が中立に比較します。","c":"ホワイトニング"},{"u":"articles/whitening-home.html","t":"市販のホワイトニングって効くの？安全なの？","d":"ドラッグストアや通販で買えるホームホワイトニング。本当に白くなるのか、しみたり歯ぐきが荒れたりしないのかを、現役歯科医師がコクランレビューをもとに正直に解説します。","c":"ホワイトニング"},{"u":"articles/whitening-toothpaste.html","t":"ホワイトニング歯磨き粉ってどこまで白くなるの？","d":"ホワイトニング歯磨き粉は本当に歯を白くするのか。着色（ステイン）にどこまで効くのか、限界はどこかを、現役歯科医師が最新のシステマティックレビューをもとに解説します。","c":"ホワイトニング"},{"u":"articles/wisdom-tooth.html","t":"親知らずって抜いた方がいいの？","d":"痛くない親知らずも抜くべき？症状のない埋伏した親知らずを「抜く」か「残す」か、コクランレビューをもとに、判断のポイントと注意点を現役歯科医師がやさしく解説します。","c":"歯内・外科"},{"u":"articles/xylitol.html","t":"キシリトールって本当に虫歯予防になるの？","d":"キシリトールのガムやタブレットは虫歯予防に効くの？コクランレビューをもとに、フッ化物歯磨剤への配合で得られた予防効果と、過度な期待をしないための注意点を現役歯科医師が解説します。","c":"オーラルケア"}];
